  ('locality-7fec267e-moex-00213', 'locality-7fec267e', 'locality-7fec267e-moex-111-3a7b2121', 'sub-locality-7fec267e-03', NULL, 'single_choice', '有關行政之敘述，下列何者錯誤？', '["行政專指行政部門所管轄的事務", "行政與政治很難嚴格劃分", "從管理的觀點，行政是一種管理技術", "從公共政策的觀點，行政與公共政策不可分割"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:21+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00214', 'locality-7fec267e', 'locality-7fec267e-moex-111-3a7b2121', 'sub-locality-7fec267e-03', NULL, 'single_choice', '政府並非當前公共事務的唯一參與者，取而代之的是跨部門合作之趨勢遞增，下列概念中何者最 能呼應這類現象？', '["公共治理", "管制治理", "公司治理", "全球治理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:21+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00215', 'locality-7fec267e', 'locality-7fec267e-moex-111-3a7b2121', 'sub-locality-7fec267e-03', NULL, 'single_choice', '我國衛生福利部成立之後，將原屬內政部的社會福利業務移撥至該部的作法，稱為：', '["組織改造", "流程簡化", "人員精簡", "協力治理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:21+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00216', 'locality-7fec267e', 'locality-7fec267e-moex-111-3a7b2121', 'sub-locality-7fec267e-03', NULL, 'single_choice', '有關我國訂定的「公民與政治權利國際公約及經濟社會文化權利國際公約施行法」，下列敘述何者 錯誤？', '["各級政府機關應依規定執行兩公約相關事項", "具有國內法律的效力", "顯示國際公約對公共行政的影響", "代表我國正式邁入先進國家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:21+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00217', 'locality-7fec267e', 'locality-7fec267e-moex-111-3a7b2121', 'sub-locality-7fec267e-03', NULL, 'single_choice', '面對公共危機時，官僚常見採取避責（blame avoidance）的行為。有關避責行為的內涵與相關策 略的敘述，下列何者錯誤？', '["避責行為係指政治人物或官僚在面臨危機時，運用策略以降低危機對治理正當性的影響", "政治人物因連任或升遷的考量，傾向避免做出不受歡迎的決策", "民主國家因為重視課責機制才存在避責現象，威權國家則無此現象", "強化透明度有助於減少避責行為的發生 30450、31350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:21+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
  ('locality-7fec267e-moex-00218', 'locality-7fec267e', 'locality-7fec267e-moex-111-3a7b2121', 'sub-locality-7fec267e-03', NULL, 'single_choice', '就美英兩國實施情形觀之，下列何者非屬支持「積極平權措施」（affirmativeaction）的理由？', '["促進社會多元性", "彌補歷史集體錯誤", "矯正制度或文化的偏差", "解決反向歧視帶來的後果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:21+00:00", "source_pdf_sha1": "d47a3a8602bd", "answer_pdf_sha1": "d5daa51a0dcf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "301", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
